-- calc_decisions_job_listing_name
-- Field: Decisions.JobListingName
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: Name from related JobListings


CREATE OR REPLACE FUNCTION calc_decisions_job_listing_name(p_decision_id TEXT)
RETURNS TEXT AS $$
  SELECT (SELECT name::text FROM job_listings WHERE job_listing_id = (SELECT job_listing FROM decisions WHERE decision_id = p_decision_id));
$$ LANGUAGE sql STABLE;

-- calc_decisions_company
-- Field: Decisions.Company
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: Company from related JobListings


CREATE OR REPLACE FUNCTION calc_decisions_company(p_decision_id TEXT)
RETURNS TEXT AS $$
  SELECT (SELECT company::text FROM job_listings WHERE job_listing_id = (SELECT job_listing FROM decisions WHERE decision_id = p_decision_id));
$$ LANGUAGE sql STABLE;

-- calc_decisions_board
-- Field: Decisions.Board
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: JobBoard from related JobListings


CREATE OR REPLACE FUNCTION calc_decisions_board(p_decision_id TEXT)
RETURNS TEXT AS $$
  SELECT (SELECT job_board::text FROM job_listings WHERE job_listing_id = (SELECT job_listing FROM decisions WHERE decision_id = p_decision_id));
$$ LANGUAGE sql STABLE;

-- calc_decisions_name
-- Field: Decisions.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_decisions_name(p_decision_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT(UPPER((SELECT NULLIF(verdict, '') FROM decisions WHERE decision_id = p_decision_id)), ': ', calc_decisions_job_listing_name(p_decision_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_decisions_is_scoring_signal
-- Field: Decisions.IsScoringSignal
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_decisions_is_scoring_signal(p_decision_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN (SELECT NULLIF(verdict, '') FROM decisions WHERE decision_id = p_decision_id) = 'yes' THEN TRUE ELSE FALSE END)::boolean;
$$ LANGUAGE sql STABLE;

